using StoreAssistantPro.Core.Commands;
using StoreAssistantPro.Models;

namespace StoreAssistantPro.Modules.Sales.Commands;

/// <summary>
/// Command to complete a sale. The <see cref="IdempotencyKey"/> is
/// generated by the caller (ViewModel) and prevents the same bill
/// from being saved twice on accidental double-click or retry.
/// </summary>
public sealed record CompleteSaleCommand(
    Guid IdempotencyKey,
    decimal TotalAmount,
    string PaymentMethod,
    IReadOnlyList<SaleItemDto> Items,
    BillDiscount Discount) : ICommandRequest<Unit>;

public sealed record SaleItemDto(
    int ProductId,
    int Quantity,
    decimal UnitPrice);
